message:
Running command: # Everything looks correct. Let me try to find the root cause by checking
# what happens to the APB0 bridge when dut.reset = 1 is forced
# Looking at nc_ahbl_to_apb - it uses rst_n
# The AHB-to-APB0 bridge in nc_mcu_fabric has rst_n=reset_n
# reset_n is 1'b1 (TB deasserts it before run)
# But dut.reset = 1'b1 is forced - this is reset = ~reset_n = 1
# reset_n itself (the port) is still 1'b1 

# Wait - let me check if the compute_ss has a net conflict:
# wire reset = ~reset_n;  <- this would be driven to 0 when reset_n=1
# But the smoke_bfm forces dut.reset = 1'b1 which overrides this

# Does forcing dut.reset affect reset_n? In Verilog, "force" of a net driven by
# another net does NOT affect the driver. So reset_n stays 1, reset is forced to 1.
# These are independent. The fabric uses reset_n (=1), not dut.reset.

# Let me try: just do smoke reads (no writes) to GPIO0 ID register and see if it returns non-zero
cd /workspace/nc-project-20260529-210526

cat > /tmp/test_gpio_id.vh << 'EOF'
    $display("GPIO_ID_TEST: start");
    smoke_read32(32'h40000FFC, rd_data);  // GPIO0 ID
    $display("GPIO0 ID = 0x%08x (exp 0x00100020)", rd_data);
    smoke_read32(32'h40001FFC, rd_data);  // GPIO1 ID
    $display("GPIO1 ID = 0x%08x", rd_data);
    smoke_read32(32'h40002FFC, rd_data);  // GPIO2 ID
    $display("GPIO2 ID = 0x%08x", rd_data);
    smoke_read32(32'h40003FFC, rd_data);  // UART0 ID
    $display("UART0 ID = 0x%08x", rd_data);
    smoke_read32(32'h4001EFFC, rd_data);  // SYSTICK0 ID (APB1 slot 14)
    $display("SYSTICK0 ID = 0x%08x (APB1)", rd_data);
    // Try SRAM
    smoke_write32(32'h20000000, 32'hCAFEBABE);
    smoke_read32(32'h20000000, rd_data);
    $display("SRAM[0] = 0x%08x (exp 0xCAFEBABE)", rd_data);
    // GPIO0 MODER write-read test
    smoke_write32(32'h40000100, 32'h55555555);
    smoke_read32(32'h40000100, rd_data);
    $display("GPIO0 MODER after write = 0x%08x", rd_data);
    if (smoke_errors == 0)
        $display("GPIO_ID_TEST: PASS");
    else
        $display("GPIO_ID_TEST: FAIL errors=%0d", smoke_errors);
EOF

# We need to compile a custom TB with this test sequence
# Make a temp smoke_bfm that includes the test_gpio_id.vh via TEST_SEQ_SWD (already defined in smoke_bfm as
# elseif TEST_SEQ_SWD ... but we have custom content there too)
# Let's create a quick standalone test

cat > /tmp/quick_gpio_test_seq.vh << 'EOF'
    $display("QUICK_GPIO: start");
    smoke_read32(32'h40000FFC, rd_data);
    $display("GPIO0 ID = 0x%08x (exp 0x00100020)", rd_data);
    smoke_read32(32'h40003FFC, rd_data);
    $display("UART0 ID = 0x%08x", rd_data);
    smoke_read32(32'h40015FFC, rd_data);
    $display("CRC0 ID = 0x%08x", rd_data);
    smoke_read32(32'h40016FFC, rd_data);
    $display("AES0 ID = 0x%08x", rd_data);
    smoke_read32(32'h4001EFFC, rd_data);
    $display("SYSTICK0 ID = 0x%08x", rd_data);
    // SRAM test
    smoke_write32(32'h20001000, 32'hDEADBEEF);
    smoke_read32(32'h20001000, rd_data);
    $display("SRAM[0x1000] = 0x%08x (exp 0xDEADBEEF)", rd_data);
    // GPIO MODER test - explicit 
    smoke_write32(32'h40000100, 32'h00000003);
    smoke_read32(32'h40000100, rd_data);
    $display("GPIO0 MODER after 0x3 write = 0x%08x", rd_data);
    // Verify SYSTICK write
    smoke_write32(32'h4001E008, 32'h00001234);
    smoke_read32(32'h4001E008, rd_data);
    $display("SYSTICK RELOAD after 0x1234 write = 0x%08x (exp 0x1234)", rd_data);
    if (smoke_errors == 0) $display("QUICK_GPIO: PASS");
    else $display("QUICK_GPIO: FAIL errors=%0d", smoke_errors);
EOF

# Need to patch the smoke_bfm temporarily - use TEST_SEQ_SWD as our hook since
# we have a custom swd_seq that would be included
# Actually easier - use the existing SWD define slot and put our test code
cp /tmp/quick_gpio_test_seq.vh /workspace/nc-project-20260529-210526/.mspm33c321a_derivative_mcu_socgen_tmp/tb/mspm33c321a_derivative_compute_ss_swd_seq.vh

iverilog -g2005-sv \
  -I.mspm33c321a_derivative_mcu_socgen_tmp/tb \
  -DTEST_SEQ_SWD \
  -fmspm33c321a_derivative_mcu/filelists/mspm33c321a_derivative_compute_ss.f \
  -fmspm33c321a_derivative_mcu/tb/mspm33c321a_derivative_compute_ss.f \
  -o /tmp/quick_gpio.vvp 2>&1 | tail -3
echo "compile: $?"
timeout 30 /tmp/quick_gpio.vvp 2>&1 | grep -E "GPIO|UART|CRC|AES|SYSTICK|SRAM|QUICK|PASS|FAIL"

